// @venom: browser
import React from "../jsx-runtime"; import type { ScoredIncident } from "../data/types"; import { age } from "../utils/format";
interface ModalProps { incident:ScoredIncident|null; onClose:()=>void; }
export default function IncidentModal({incident,onClose}:ModalProps){ if(!incident)return null; return <div className="modal-backdrop" onClick={onClose}><section className="incident-modal" onClick={(event)=>event.stopPropagation()}><button className="modal-close" onClick={onClose}>×</button><p className="eyebrow">{incident.id}</p><h2>{incident.title}</h2><div className={`modal-risk ${incident.riskBand.toLowerCase()}`}><strong>{incident.riskScore}</strong><span>{incident.riskBand} risk</span></div><dl><div><dt>Service</dt><dd>{incident.service}</dd></div><div><dt>Region</dt><dd>{incident.region}</dd></div><div><dt>Owner</dt><dd>{incident.owner}</dd></div><div><dt>Age</dt><dd>{age(incident.ageMinutes)}</dd></div><div><dt>Signals</dt><dd>{incident.signals}</dd></div><div><dt>Confidence</dt><dd>{incident.confidence}%</dd></div></dl><div className="recommendation"><small>Protected recommendation</small><strong>{incident.recommendedAction}</strong></div><button className="primary-button wide" onClick={onClose}>Acknowledge incident</button></section></div>; }
